Here's how to handle each scenario with modern MSTest (3.9+):

```csharp
[TestClass]
public sealed class SpecializedTests : IDisposable
{
    private readonly List<string> _tempFiles = [];

    // 1. Windows-only (MSTest 3.10+)
    [TestMethod]
    [OSCondition(OperatingSystems.Windows)]
    public void Registry_ReadsExpectedValue()
    {
        var value = Registry.GetValue(@"HKEY_LOCAL_MACHINE\SOFTWARE\...", "Key", null);
        Assert.IsNotNull(value);
    }

    // 2. Skip in CI (MSTest 3.10+)
    [TestMethod]
    [CICondition(ConditionMode.Exclude)]
    public void GpuCompute_ProducesCorrectOutput()
    {
        var result = GpuProcessor.Run(inputData);
        Assert.AreEqual(expected, result);
    }

    // 3. Flaky external API — retry (MSTest 3.9+)
    [TestMethod]
    [Retry(3)]
    [Timeout(10000)]
    public async Task WeatherApi_ReturnsForecast(TestContext testContext)
    {
        var forecast = await _weatherClient.GetForecastAsync(testContext.CancellationToken);
        Assert.IsNotNull(forecast);
    }

    // 4. Temp file cleanup — use TestCleanup or IDisposable
    [TestMethod]
    public void Export_CreatesValidFile()
    {
        var path = Path.GetTempFileName();
        _tempFiles.Add(path);

        Exporter.WriteTo(path);

        Assert.IsNotEmpty(File.ReadAllText(path));
    }

    // Runs even if the test fails
    public void Dispose()
    {
        foreach (var file in _tempFiles)
        {
            if (File.Exists(file))
                File.Delete(file);
        }
    }
}
```

**Summary of attributes:**

| Scenario | Solution |
|----------|----------|
| Windows-only | `[OSCondition(OperatingSystems.Windows)]` |
| Skip in CI | `[CICondition(ConditionMode.Exclude)]` |
| Flaky external dep | `[Retry(3)]` |
| Cleanup on failure | `IDisposable` or `[TestCleanup]` |

**Notes:**
- `[OSCondition]` and `[CICondition]` skip (not fail) when conditions aren't met
- `[Retry]` should only mask genuine external flakiness, not race conditions
- For cleanup, `IDisposable`/`IAsyncDisposable` is preferred over `[TestCleanup]` since it enables `readonly` fields and works naturally with the constructor pattern
